import{o as a,c as e,d as s}from"./app.4dc82166.js";const n='{"title":"控制器","description":"","frontmatter":{"title":"控制器"},"headers":[{"level":2,"title":"ReplicaSet","slug":"replicaset"},{"level":2,"title":"Deployments","slug":"deployments"},{"level":3,"title":"创建","slug":"创建"},{"level":3,"title":"更新","slug":"更新"},{"level":3,"title":"回滚","slug":"回滚"},{"level":3,"title":"伸缩","slug":"伸缩"},{"level":2,"title":"StatefulSets","slug":"statefulsets"},{"level":2,"title":"DaemonSet","slug":"daemonset"},{"level":2,"title":"Jobs","slug":"jobs"},{"level":2,"title":"CronJob","slug":"cronjob"}],"relativePath":"docs/cloud-native/kubernetes/workloads/controller.md","lastUpdated":1654181850206}',t={},l=s('<p>Kubernetes 中内建了很多的 controller（控制器），这些控制器相当于一个状态机，用来控制 Pod 的具体状态和行为</p><h2 id="replicaset"><a class="header-anchor" href="#replicaset" aria-hidden="true">#</a> ReplicaSet</h2><h2 id="deployments"><a class="header-anchor" href="#deployments" aria-hidden="true">#</a> Deployments</h2><p>一个 Deployment 为 Pods 和 ReplicaSets 提供声明式的更新能力。</p><h3 id="创建"><a class="header-anchor" href="#创建" aria-hidden="true">#</a> 创建</h3><p>下面是一个 Deployment 示例。其中创建了一个 ReplicaSet，负责启动三个 myhttp Pods：</p><div class="language-yaml"><pre><code><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1\n<span class="token key atrule">kind</span><span class="token punctuation">:</span> Deployment\n<span class="token key atrule">metadata</span><span class="token punctuation">:</span>\n  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> test\n  <span class="token key atrule">name</span><span class="token punctuation">:</span> myhttp\n  <span class="token key atrule">labels</span><span class="token punctuation">:</span>\n    <span class="token key atrule">app</span><span class="token punctuation">:</span> myhttp\n<span class="token key atrule">spec</span><span class="token punctuation">:</span>\n  <span class="token key atrule">replicas</span><span class="token punctuation">:</span> <span class="token number">3</span>\n  <span class="token key atrule">selector</span><span class="token punctuation">:</span>\n    <span class="token key atrule">matchLabels</span><span class="token punctuation">:</span>\n      <span class="token key atrule">app</span><span class="token punctuation">:</span> myhttp\n  <span class="token key atrule">template</span><span class="token punctuation">:</span>\n    <span class="token key atrule">metadata</span><span class="token punctuation">:</span>\n      <span class="token key atrule">labels</span><span class="token punctuation">:</span>\n        <span class="token key atrule">app</span><span class="token punctuation">:</span> myhttp\n    <span class="token key atrule">spec</span><span class="token punctuation">:</span>\n      <span class="token key atrule">containers</span><span class="token punctuation">:</span>\n      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> myhttp\n        <span class="token key atrule">image</span><span class="token punctuation">:</span> myhttp<span class="token punctuation">:</span>v1\n        <span class="token key atrule">imagePullPolicy</span><span class="token punctuation">:</span> IfNotPresent\n        <span class="token key atrule">ports</span><span class="token punctuation">:</span>\n        <span class="token punctuation">-</span> <span class="token key atrule">containerPort</span><span class="token punctuation">:</span> <span class="token number">9090</span>\n</code></pre></div><ol><li>通过运行以下命令创建 Deployment ：</li></ol><div class="language-shell"><pre><code>kubectl apply -f myhttp.yml\n</code></pre></div><ol start="2"><li>检查 Deployment 是否已创建。</li></ol><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@node1 ~<span class="token punctuation">]</span><span class="token comment"># kubectl get deployments -n test</span>\nNAME     READY   UP-TO-DATE   AVAILABLE   AGE\nmyhttp   <span class="token number">3</span>/3     <span class="token number">3</span>            <span class="token number">3</span>           6d6h\n</code></pre></div><h3 id="更新"><a class="header-anchor" href="#更新" aria-hidden="true">#</a> 更新</h3><ul><li>set 命令行更新</li></ul><div class="language-shell"><pre><code>kubectl <span class="token builtin class-name">set</span> image deployment/myhttp <span class="token assign-left variable">myhttp</span><span class="token operator">=</span>docker.io/library/myhttp:v2 --record\n</code></pre></div><ul><li>edit 修改文件更新</li></ul><p><code>.spec.template.spec.containers[0].image</code> 从 <code>myhttp:v1</code> 更改为 <code>myhttp:v2</code></p><div class="language-shell"><pre><code>kubectl edit deployment myhttp -n <span class="token builtin class-name">test</span>\n</code></pre></div><h4 id="更新策略"><a class="header-anchor" href="#更新策略" aria-hidden="true">#</a> 更新策略</h4><ol><li>重新构建（Recreate）</li></ol><p><code>.spec.strategy.type==Recreate</code> 在创建新 Pods 之前，所有现有的 Pods 会被杀死。</p><ol start="2"><li>滚动更新（RollingUpdate）</li></ol><p><code>.spec.strategy.type==RollingUpdate</code> 采取滚动更新的方式更新 Pods。可以指定 maxUnavailable 和 maxSurge 来控制滚动更新 过程。</p><p>最大不可用 <code>.spec.strategy.rollingUpdate.maxUnavailable</code> 是一个可选字段，用来指定更新过程中不可用的 Pod 的个数上限</p><p>最大峰值 <code>.spec.strategy.rollingUpdate.maxSurge</code> 是一个可选字段，用来指定可以创建的超出期望 Pod 个数的 Pod 数量。此值可以是绝对数（例如，5）或所需 Pods 的百分比（例如，10%）。</p><h3 id="回滚"><a class="header-anchor" href="#回滚" aria-hidden="true">#</a> 回滚</h3><ol><li>首先，检查 Deployment 修订历史：</li></ol><div class="language-shell"><pre><code>kubectl rollout <span class="token function">history</span> deployment/myhttp\n</code></pre></div><ol start="2"><li>要查看修订历史的详细信息，运行：</li></ol><div class="language-shell"><pre><code>kubectl rollout <span class="token function">history</span> deployment/myhttp --revision<span class="token operator">=</span><span class="token number">1</span>\n</code></pre></div><ol start="3"><li>回滚到之前的修订版本（即版本1）</li></ol><div class="language-shell"><pre><code>kubectl rollout undo deployment/myhttp --to-revision<span class="token operator">=</span><span class="token number">1</span>\n</code></pre></div><h3 id="伸缩"><a class="header-anchor" href="#伸缩" aria-hidden="true">#</a> 伸缩</h3><ul><li>手动伸缩</li></ul><div class="language-shell"><pre><code>kubectl scale deployment/myhttp --replicas<span class="token operator">=</span><span class="token number">10</span> -n <span class="token builtin class-name">test</span>\n</code></pre></div><ul><li>自动伸缩</li></ul><p>根据一定的条件自动伸缩</p><div class="language-shell"><pre><code>kubectl autoscale deployment/myhttp -n <span class="token builtin class-name">test</span> --min<span class="token operator">=</span><span class="token number">10</span> --max<span class="token operator">=</span><span class="token number">15</span> --cpu-percent<span class="token operator">=</span><span class="token number">80</span>\n</code></pre></div><h2 id="statefulsets"><a class="header-anchor" href="#statefulsets" aria-hidden="true">#</a> StatefulSets</h2><h2 id="daemonset"><a class="header-anchor" href="#daemonset" aria-hidden="true">#</a> DaemonSet</h2><h2 id="jobs"><a class="header-anchor" href="#jobs" aria-hidden="true">#</a> Jobs</h2><h2 id="cronjob"><a class="header-anchor" href="#cronjob" aria-hidden="true">#</a> CronJob</h2>',41);t.render=function(s,n,t,p,o,c){return a(),e("div",null,[l])};export default t;export{n as __pageData};
